    .ispr_base_wr_en_i        (ispr_base_wr_en),
    .ispr_bignum_wdata_i      (ispr_bignum_wdata),
    .ispr_bignum_wr_en_i      (ispr_bignum_wr_en),
    .ispr_init_i              (ispr_init),
    .ispr_rdata_o             (ispr_rdata),

    .ispr_acc_i               (ispr_acc),
