    .rd_data_a_intg_o (rf_bignum_rd_data_a_intg),
    .rd_addr_b_i      (rf_bignum_rd_addr_b),
    .rd_en_b_i        (rf_bignum_rd_en_b),
    .rd_data_b_intg_o (rf_bignum_rd_data_b_intg),

    .rd_data_err_o (rf_bignum_rd_data_err)
