  ) u_err_bits_fatal_imem (
    .clk_i   (clk_i    ),
    .rst_ni  (rst_ni  ),

    .we     (1'b0),
    .wd     ('0  ),

    // from internal hardware
    .de     (hw2reg.err_bits.fatal_imem.de),
    .d      (hw2reg.err_bits.fatal_imem.d ),

