  ) u_err_bits_fatal_reg (
    .clk_i   (clk_i    ),
    .rst_ni  (rst_ni  ),

    .we     (1'b0),
    .wd     ('0  ),

    // from internal hardware
    .de     (hw2reg.err_bits.fatal_reg.de),
    .d      (hw2reg.err_bits.fatal_reg.d ),

